mapper.update:
UPDATE participation p
SET p.status = #{targetStatus}
WHERE p.id = #{participationId}
  AND  = #{currentStatus}

mapper.select:
SELECT p.id AS participationId, p.schedule_id AS scheduleId, u.id AS userId, u.email AS email, u.nickname AS nickname, AS status, p.created_at AS createdAt FROM participation p INNER JOIN user u ON u.id = p.user_id WHERE p.schedule_id = #{scheduleId}
AND = #{status}
ORDER BY p.id DESC

mapper.update:
UPDATE participation p
INNER JOIN user u ON u.id = p.user_id
SET p.status = 'CANCELLED'
WHERE p.id = #{participationId}
  AND u.email = #{email}
  AND UPPER(p.status) = 'PENDING'

mapper.delete:
DELETE p
FROM participation p
INNER JOIN user u ON u.id = p.user_id
WHERE p.id = #{participationId}
  AND u.email = #{email}
  AND UPPER(p.status) IN ('REJECTED', 'KICKED')
